vals_range = find(V_dm_25dV_60dV > -0.1 & V_dm_25dV_60dV < 0.1);
plot_range = linspace(-0.15, 0.15, 101);
tmp = (I_out1_25dV_60dV - I_out2_25dV_60dV);
fit_vals = polyfit(V_dm_25dV_60dV(vals_range), tmp(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Incremental Differential-Mode Transconductance Gain: y = ', num2str(fit_vals(1), 3), 'x ', char(8487), ' + ', num2str(fit_vals(2), 3), ' V']) %[output:1eb8f6e5]

